// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract LeaseRegistry {
    struct Lease {
        address tenant;
        address landlord;
        uint256 monthlyRentUsdCents;
        uint8 dueDay;
        uint64 startTimestamp;
        bool active;
    }

    mapping(bytes32 => Lease) private leases;
    mapping(address => bytes32[]) private tenantLeaseIds;

    event LeaseRegistered(
        bytes32 indexed leaseId,
        address indexed tenant,
        address indexed landlord,
        uint256 monthlyRentUsdCents,
        uint8 dueDay
    );

    function registerLease(
        address tenant,
        address landlord,
        uint256 monthlyRentUsdCents,
        uint8 dueDay
    ) external returns (bytes32 leaseId) {
        require(tenant != address(0), "tenant required");
        require(landlord != address(0), "landlord required");
        require(monthlyRentUsdCents > 0, "rent required");
        require(dueDay > 0 && dueDay <= 28, "invalid due day");

        leaseId = keccak256(
            abi.encodePacked(
                tenant,
                landlord,
                monthlyRentUsdCents,
                dueDay,
                block.timestamp,
                tenantLeaseIds[tenant].length
            )
        );

        require(!leases[leaseId].active, "lease exists");

        leases[leaseId] = Lease({
            tenant: tenant,
            landlord: landlord,
            monthlyRentUsdCents: monthlyRentUsdCents,
            dueDay: dueDay,
            startTimestamp: uint64(block.timestamp),
            active: true
        });

        tenantLeaseIds[tenant].push(leaseId);

        emit LeaseRegistered(
            leaseId,
            tenant,
            landlord,
            monthlyRentUsdCents,
            dueDay
        );
    }

    function getLease(
        bytes32 leaseId
    )
        external
        view
        returns (
            address tenant,
            address landlord,
            uint256 monthlyRentUsdCents,
            uint8 dueDay,
            uint64 startTimestamp,
            bool active
        )
    {
        Lease memory leaseData = leases[leaseId];
        return (
            leaseData.tenant,
            leaseData.landlord,
            leaseData.monthlyRentUsdCents,
            leaseData.dueDay,
            leaseData.startTimestamp,
            leaseData.active
        );
    }

    function getLeaseStruct(
        bytes32 leaseId
    ) external view returns (Lease memory) {
        return leases[leaseId];
    }

    function getTenantLeases(address tenant) external view returns (bytes32[] memory) {
        return tenantLeaseIds[tenant];
    }
}

contracts/LoanGateway.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IRentScoreReader {
    function getScore(address tenant) external view returns (uint16);
}

contract LoanGateway {
    enum LoanStatus {
        NONE,
        ACTIVE,
        PAID,
        DEFAULTED
    }

    struct Loan {
        bytes32 loanId;
        address borrower;
        uint8 tier;
        uint256 principalUsdCents;
        uint256 outstandingUsdCents;
        uint16 aprBps;
        uint64 createdAt;
        LoanStatus status;
    }

    IRentScoreReader public immutable rentScoreReader;

    mapping(bytes32 => Loan) public loans;
    mapping(address => bytes32[]) public borrowerLoanIds;

    event LoanRequested(
        bytes32 indexed loanId,
        address indexed borrower,
        uint8 tier,
        uint256 amountUsdCents
    );
    event LoanActivated(
        bytes32 indexed loanId,
        address indexed borrower,
        uint256 principalUsdCents,
        uint16 aprBps
    );
    event LoanRepaid(
        bytes32 indexed loanId,
        address indexed borrower,
        uint256 amountUsdCents,
        uint256 remainingUsdCents
    );

    constructor(address rentScoreReaderAddress) {
        require(rentScoreReaderAddress != address(0), "score reader required");
        rentScoreReader = IRentScoreReader(rentScoreReaderAddress);
    }

    function requestLoan(
        uint8 tier,
        uint256 amountUsdCents
    ) external returns (bytes32 loanId) {
        require(amountUsdCents > 0, "amount required");
        (uint16 minScore, uint256 maxAmountUsdCents, uint16 aprBps) = _tierConfig(
            tier
        );

        uint16 score = rentScoreReader.getScore(msg.sender);
        require(score >= minScore, "score too low");
        require(amountUsdCents <= maxAmountUsdCents, "amount exceeds tier");

        loanId = keccak256(
            abi.encodePacked(
                msg.sender,
                tier,
                amountUsdCents,
                block.timestamp,
                borrowerLoanIds[msg.sender].length
            )
        );

        Loan storage loan = loans[loanId];
        require(loan.status == LoanStatus.NONE, "loan exists");

        loans[loanId] = Loan({
            loanId: loanId,
            borrower: msg.sender,
            tier: tier,
            principalUsdCents: amountUsdCents,
            outstandingUsdCents: amountUsdCents,
            aprBps: aprBps,
            createdAt: uint64(block.timestamp),
            status: LoanStatus.ACTIVE
        });

        borrowerLoanIds[msg.sender].push(loanId);

        emit LoanRequested(loanId, msg.sender, tier, amountUsdCents);
        emit LoanActivated(loanId, msg.sender, amountUsdCents, aprBps);
    }

    function repayLoan(bytes32 loanId, uint256 amountUsdCents) external {
        require(amountUsdCents > 0, "amount required");
        Loan storage loan = loans[loanId];
        require(loan.status == LoanStatus.ACTIVE, "loan inactive");
        require(loan.borrower == msg.sender, "only borrower");

        if (amountUsdCents >= loan.outstandingUsdCents) {
            loan.outstandingUsdCents = 0;
            loan.status = LoanStatus.PAID;
        } else {
            loan.outstandingUsdCents -= amountUsdCents;
        }

        emit LoanRepaid(loanId, msg.sender, amountUsdCents, loan.outstandingUsdCents);
    }

    function getLoanStatus(
        bytes32 loanId
    )
        external
        view
        returns (
            address borrower,
            uint8 tier,
            uint256 principalUsdCents,
            uint256 outstandingUsdCents,
            uint16 aprBps,
            uint64 createdAt,
            LoanStatus status
        )
    {
        Loan memory loan = loans[loanId];
        return (
            loan.borrower,
            loan.tier,
            loan.principalUsdCents,
            loan.outstandingUsdCents,
            loan.aprBps,
            loan.createdAt,
            loan.status
        );
    }

    function _tierConfig(
        uint8 tier
    ) internal pure returns (uint16 minScore, uint256 maxAmountUsdCents, uint16 aprBps) {
        if (tier == 1) return (300, 10000 * 100, 1800);
        if (tier == 2) return (450, 30000 * 100, 1500);
        if (tier == 3) return (600, 75000 * 100, 1200);
        if (tier == 4) return (700, 150000 * 100, 1000);
        revert("invalid tier");
    }
}

contracts/PaymentRecordNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {ERC721} from "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

contract PaymentRecordNFT is ERC721, Ownable {
    struct PaymentRecord {
        bytes32 paymentRecordId;
        bytes32 leaseId;
        uint256 amountUsdCents;
        uint8 statusCode; // 1 = ON_TIME, 2 = LATE
        uint64 timestamp;
        bytes32 txRef;
    }

    uint256 public nextTokenId;
    mapping(uint256 => PaymentRecord) private recordsByTokenId;
    mapping(address => uint256[]) private tenantTokenIds;

    event CertificateIssued(
        uint256 indexed tokenId,
        address indexed tenant,
        bytes32 indexed paymentRecordId,
        bytes32 leaseId,
        uint256 amountUsdCents,
        uint8 statusCode
    );

    error Soulbound();

    constructor() ERC721("RentLedger Payment Certificate", "RLPC") {}

    function mintCertificate(
        address tenant,
        bytes32 paymentRecordId,
        bytes32 leaseId,
        uint256 amountUsdCents,
        uint8 statusCode,
        bytes32 txRef
    ) external onlyOwner returns (uint256 tokenId) {
        require(tenant != address(0), "tenant required");
        require(amountUsdCents > 0, "amount required");
        require(statusCode == 1 || statusCode == 2, "invalid status");

        nextTokenId += 1;
        tokenId = nextTokenId;

        _safeMint(tenant, tokenId);

        recordsByTokenId[tokenId] = PaymentRecord({
            paymentRecordId: paymentRecordId,
            leaseId: leaseId,
            amountUsdCents: amountUsdCents,
            statusCode: statusCode,
            timestamp: uint64(block.timestamp),
            txRef: txRef
        });

        tenantTokenIds[tenant].push(tokenId);

        emit CertificateIssued(
            tokenId,
            tenant,
            paymentRecordId,
            leaseId,
            amountUsdCents,
            statusCode
        );
    }

    function getPaymentTokenIds(address tenant) external view returns (uint256[] memory) {
        return tenantTokenIds[tenant];
    }

    function getPaymentRecord(
        uint256 tokenId
    ) external view returns (PaymentRecord memory) {
        require(_exists(tokenId), "token not found");
        return recordsByTokenId[tokenId];
    }

    function getPaymentRecordFields(
        uint256 tokenId
    )
        external
        view
        returns (
            bytes32 paymentRecordId,
            bytes32 leaseId,
            uint256 amountUsdCents,
            uint8 statusCode,
            uint64 timestamp,
            bytes32 txRef
        )
    {
        require(_exists(tokenId), "token not found");
        PaymentRecord memory record = recordsByTokenId[tokenId];
        return (
            record.paymentRecordId,
            record.leaseId,
            record.amountUsdCents,
            record.statusCode,
            record.timestamp,
            record.txRef
        );
    }

    function getScoreInputs(
        uint256 tokenId
    ) external view returns (uint256 amountUsdCents, uint8 statusCode, uint64 timestamp) {
        require(_exists(tokenId), "token not found");
        PaymentRecord memory record = recordsByTokenId[tokenId];
        return (record.amountUsdCents, record.statusCode, record.timestamp);
    }

    function approve(address, uint256) public pure override {
        revert Soulbound();
    }

    function setApprovalForAll(address, bool) public pure override {
        revert Soulbound();
    }

    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId,
        uint256 batchSize
    ) internal override {
        super._beforeTokenTransfer(from, to, tokenId, batchSize);
        if (from != address(0) && to != address(0)) {
            revert Soulbound();
        }
    }
}

contracts/RentScoreReader.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IPaymentRecordNFT {
    function getPaymentTokenIds(address tenant) external view returns (uint256[] memory);

    function getScoreInputs(
        uint256 tokenId
    ) external view returns (uint256 amountUsdCents, uint8 statusCode, uint64 timestamp);
}

contract RentScoreReader {
    IPaymentRecordNFT public immutable paymentRecordNFT;

    event ScoreSnapshotStored(
        address indexed tenant,
        uint16 score,
        bytes32 snapshotId
    );

    constructor(address paymentRecordNFTAddress) {
        require(paymentRecordNFTAddress != address(0), "payment nft required");
        paymentRecordNFT = IPaymentRecordNFT(paymentRecordNFTAddress);
    }

    function getPaymentCount(address tenant) external view returns (uint256) {
        return paymentRecordNFT.getPaymentTokenIds(tenant).length;
    }

    function getScore(address tenant) public view returns (uint16) {
        uint256[] memory tokenIds = paymentRecordNFT.getPaymentTokenIds(tenant);
        if (tokenIds.length == 0) {
            return 150;
        }

        uint256 onTimeCount = 0;
        uint256 lateCount = 0;
        uint256 amountSum = 0;
        uint64 firstTimestamp = type(uint64).max;
        uint64 latestTimestamp = 0;

        uint256 start = tokenIds.length > 6 ? tokenIds.length - 6 : 0;
        uint256 recentOnTimeCount = 0;

        for (uint256 i = 0; i < tokenIds.length; i++) {
            (uint256 amountUsdCents, uint8 statusCode, uint64 paymentTs) = paymentRecordNFT
                .getScoreInputs(tokenIds[i]);

            amountSum += amountUsdCents;

            if (statusCode == 1) {
                onTimeCount += 1;
            } else if (statusCode == 2) {
                lateCount += 1;
            }

            if (paymentTs < firstTimestamp) firstTimestamp = paymentTs;
            if (paymentTs > latestTimestamp) latestTimestamp = paymentTs;

            if (i >= start && statusCode == 1) {
                recentOnTimeCount += 1;
            }
        }

        int256 score = 150;

        uint256 onTimePoints = onTimeCount * 30;
        if (onTimePoints > 300) onTimePoints = 300;
        score += int256(onTimePoints);

        if (tokenIds.length >= 6 && recentOnTimeCount == 6) {
            score += 50;
        }

        uint256 avgAmount = amountSum / tokenIds.length;
        if (avgAmount >= 100000) {
            score += 50;
        } else if (avgAmount >= 50000) {
            score += 30;
        } else {
            score += 10;
        }

        if (latestTimestamp > firstTimestamp) {
            uint256 tenureMonths = (latestTimestamp - firstTimestamp) / 30 days;
            if (tenureMonths >= 12) {
                score += 50;
            } else if (tenureMonths >= 6) {
                score += 25;
            }
        }

        score -= int256(lateCount * 15);

        if (score < 0) score = 0;
        if (score > 850) score = 850;
        return uint16(uint256(score));
    }

    function isEligible(
        address tenant,
        uint8 tier
    ) external view returns (bool) {
        uint16 score = getScore(tenant);
        return score >= _tierMinScore(tier);
    }

    function snapshotScore(address tenant) external returns (bytes32 snapshotId, uint16 score) {
        score = getScore(tenant);
        snapshotId = keccak256(abi.encodePacked(tenant, score, block.timestamp));
        emit ScoreSnapshotStored(tenant, score, snapshotId);
    }

    function _tierMinScore(uint8 tier) internal pure returns (uint16) {
        if (tier == 1) return 300;
        if (tier == 2) return 450;
        if (tier == 3) return 600;
        if (tier == 4) return 700;
        revert("invalid tier");
    }
}

